26: func VerbMatches(rule *rbacv1.PolicyRule, requestedVerb string) bool {
27: 	for _, ruleVerb := range rule.Verbs {
28: 		if ruleVerb == rbacv1.VerbAll {
29: 			return true
30: 		}
31: 		if ruleVerb == requestedVerb {
32: 			return true
33: 		}
34: 	}
35: 
36: 	return false
37: }
38: 
39: func APIGroupMatches(rule *rbacv1.PolicyRule, requestedGroup string) bool {
40: 	for _, ruleGroup := range rule.APIGroups {
41: 		if ruleGroup == rbacv1.APIGroupAll {
42: 			return true
43: 		}
44: 		if ruleGroup == requestedGroup {
45: 			return true
46: 		}
47: 	}
48: 
49: 	return false
50: }
51: 
52: func ResourceMatches(rule *rbacv1.PolicyRule, combinedRequestedResource, requestedSubresource string) bool {
53: 	for _, ruleResource := range rule.Resources {
54: 		// if everything is allowed, we match
55: 		if ruleResource == rbacv1.ResourceAll {
56: 			return true
57: 		}
58: 		// if we have an exact match, we match
59: 		if ruleResource == combinedRequestedResource {
60: 			return true
61: 		}
62: 
63: 		// We can also match a */subresource.
64: 		// if there isn't a subresource, then continue
65: 		if len(requestedSubresource) == 0 {
66: 			continue
67: 		}
68: 		// if the rule isn't in the format */subresource, then we don't match, continue
69: 		if len(ruleResource) == len(requestedSubresource)+2 &&
70: 			strings.HasPrefix(ruleResource, "*/") &&
71: 			strings.HasSuffix(ruleResource, requestedSubresource) {
72: 			return true
73: 
74: 		}
75: 	}
76: 
77: 	return false
78: }
79: 
80: func ResourceNameMatches(rule *rbacv1.PolicyRule, requestedName string) bool {
81: 	if len(rule.ResourceNames) == 0 {
82: 		return true
83: 	}
84: 
85: 	for _, ruleName := range rule.ResourceNames {
86: 		if ruleName == requestedName {
87: 			return true
88: 		}
89: 	}
90: 
91: 	return false
92: }
93: 
94: func NonResourceURLMatches(rule *rbacv1.PolicyRule, requestedURL string) bool {
95: 	for _, ruleURL := range rule.NonResourceURLs {
96: 		if ruleURL == rbacv1.NonResourceAll {
97: 			return true
98: 		}
99: 		if ruleURL == requestedURL {
100: 			return true
101: 		}
102: 		if strings.HasSuffix(ruleURL, "*") && strings.HasPrefix(requestedURL, strings.TrimRight(ruleURL, "*")) {
103: 			return true
104: 		}
105: 	}
106: 
107: 	return false
108: }
