110: // CompactString exposes a compact string representation for use in escalation error messages
111: func CompactString(r rbacv1.PolicyRule) string {
112: 	formatStringParts := []string{}
113: 	formatArgs := []interface{}{}
114: 	if len(r.APIGroups) > 0 {
115: 		formatStringParts = append(formatStringParts, "APIGroups:%q")
116: 		formatArgs = append(formatArgs, r.APIGroups)
117: 	}
118: 	if len(r.Resources) > 0 {
119: 		formatStringParts = append(formatStringParts, "Resources:%q")
120: 		formatArgs = append(formatArgs, r.Resources)
121: 	}
122: 	if len(r.NonResourceURLs) > 0 {
123: 		formatStringParts = append(formatStringParts, "NonResourceURLs:%q")
124: 		formatArgs = append(formatArgs, r.NonResourceURLs)
125: 	}
126: 	if len(r.ResourceNames) > 0 {
127: 		formatStringParts = append(formatStringParts, "ResourceNames:%q")
128: 		formatArgs = append(formatArgs, r.ResourceNames)
129: 	}
130: 	if len(r.Verbs) > 0 {
131: 		formatStringParts = append(formatStringParts, "Verbs:%q")
132: 		formatArgs = append(formatArgs, r.Verbs)
133: 	}
134: 	formatString := "{" + strings.Join(formatStringParts, ", ") + "}"
135: 	return fmt.Sprintf(formatString, formatArgs...)
136: }
