31: 
32: // PolicyRuleBuilder let's us attach methods.  A no-no for API types.
33: // We use it to construct rules in code.  It's more compact than trying to write them
34: // out in a literal and allows us to perform some basic checking during construction
35: type PolicyRuleBuilder struct {
36: 	PolicyRule rbacv1.PolicyRule `protobuf:"bytes,1,opt,name=policyRule"`
37: }
38: 
39: func NewRule(verbs ...string) *PolicyRuleBuilder {
40: 	return &PolicyRuleBuilder{
41: 		PolicyRule: rbacv1.PolicyRule{Verbs: sets.NewString(verbs...).List()},
42: 	}
43: }
44: 
45: func (r *PolicyRuleBuilder) Groups(groups ...string) *PolicyRuleBuilder {
46: 	r.PolicyRule.APIGroups = combine(r.PolicyRule.APIGroups, groups)
47: 	return r
48: }
49: 
50: func (r *PolicyRuleBuilder) Resources(resources ...string) *PolicyRuleBuilder {
51: 	r.PolicyRule.Resources = combine(r.PolicyRule.Resources, resources)
52: 	return r
53: }
54: 
55: func (r *PolicyRuleBuilder) Names(names ...string) *PolicyRuleBuilder {
56: 	r.PolicyRule.ResourceNames = combine(r.PolicyRule.ResourceNames, names)
57: 	return r
58: }
59: 
60: func (r *PolicyRuleBuilder) URLs(urls ...string) *PolicyRuleBuilder {
61: 	r.PolicyRule.NonResourceURLs = combine(r.PolicyRule.NonResourceURLs, urls)
62: 	return r
63: }
64: 
65: func combine(s1, s2 []string) []string {
66: 	s := sets.NewString(s1...)
67: 	s.Insert(s2...)
68: 	return s.List()
69: }
70: 
71: func (r *PolicyRuleBuilder) RuleOrDie() rbacv1.PolicyRule {
72: 	ret, err := r.Rule()
73: 	if err != nil {
74: 		panic(err)
75: 	}
76: 	return ret
77: }
78: 
79: func (r *PolicyRuleBuilder) Rule() (rbacv1.PolicyRule, error) {
80: 	if len(r.PolicyRule.Verbs) == 0 {
81: 		return rbacv1.PolicyRule{}, fmt.Errorf("verbs are required: %#v", r.PolicyRule)
82: 	}
83: 
84: 	switch {
85: 	case len(r.PolicyRule.NonResourceURLs) > 0:
86: 		if len(r.PolicyRule.APIGroups) != 0 || len(r.PolicyRule.Resources) != 0 || len(r.PolicyRule.ResourceNames) != 0 {
87: 			return rbacv1.PolicyRule{}, fmt.Errorf("non-resource rule may not have apiGroups, resources, or resourceNames: %#v", r.PolicyRule)
88: 		}
89: 	case len(r.PolicyRule.Resources) > 0:
90: 		if len(r.PolicyRule.NonResourceURLs) != 0 {
91: 			return rbacv1.PolicyRule{}, fmt.Errorf("resource rule may not have nonResourceURLs: %#v", r.PolicyRule)
92: 		}
93: 		if len(r.PolicyRule.APIGroups) == 0 {
94: 			// this a common bug
95: 			return rbacv1.PolicyRule{}, fmt.Errorf("resource rule must have apiGroups: %#v", r.PolicyRule)
96: 		}
97: 	default:
98: 		return rbacv1.PolicyRule{}, fmt.Errorf("a rule must have either nonResourceURLs or resources: %#v", r.PolicyRule)
99: 	}
100: 
101: 	sort.Strings(r.PolicyRule.Resources)
102: 	sort.Strings(r.PolicyRule.ResourceNames)
103: 	sort.Strings(r.PolicyRule.APIGroups)
104: 	sort.Strings(r.PolicyRule.NonResourceURLs)
105: 	sort.Strings(r.PolicyRule.Verbs)
106: 	return r.PolicyRule, nil
107: }
