111: // ClusterRoleBindingBuilder let's us attach methods.  A no-no for API types.
112: // We use it to construct bindings in code.  It's more compact than trying to write them
113: // out in a literal.
114: type ClusterRoleBindingBuilder struct {
115: 	ClusterRoleBinding rbacv1.ClusterRoleBinding `protobuf:"bytes,1,opt,name=clusterRoleBinding"`
116: }
117: 
118: func NewClusterBinding(clusterRoleName string) *ClusterRoleBindingBuilder {
119: 	return &ClusterRoleBindingBuilder{
120: 		ClusterRoleBinding: rbacv1.ClusterRoleBinding{
121: 			ObjectMeta: metav1.ObjectMeta{Name: clusterRoleName},
122: 			RoleRef: rbacv1.RoleRef{
123: 				APIGroup: GroupName,
124: 				Kind:     "ClusterRole",
125: 				Name:     clusterRoleName,
126: 			},
127: 		},
128: 	}
129: }
130: 
131: func (r *ClusterRoleBindingBuilder) Groups(groups ...string) *ClusterRoleBindingBuilder {
132: 	for _, group := range groups {
133: 		r.ClusterRoleBinding.Subjects = append(r.ClusterRoleBinding.Subjects, rbacv1.Subject{APIGroup: rbacv1.GroupName, Kind: rbacv1.GroupKind, Name: group})
134: 	}
135: 	return r
136: }
137: 
138: func (r *ClusterRoleBindingBuilder) Users(users ...string) *ClusterRoleBindingBuilder {
139: 	for _, user := range users {
140: 		r.ClusterRoleBinding.Subjects = append(r.ClusterRoleBinding.Subjects, rbacv1.Subject{APIGroup: rbacv1.GroupName, Kind: rbacv1.UserKind, Name: user})
